+		if !errors.As(err, &exitErr) || exitErr.Code != 0 {
+			t.Fatalf("expected dry-run exit, got %v", err)
+		}
+	})
+	if !strings.Contains(out, "drive.delete") {
+		t.Fatalf("expected op in output, got %q", out)
+	}
+}
